using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = "";

    [LoadColumn(1)]
    public string Description { get; set; } = "";

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = "";
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public sealed class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = "";
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public sealed class TrainingMetrics
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public string ConfusionMatrix { get; set; } = "";
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelTrainer
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    // Category labels in the order ML.NET assigns them (alphabetical by default)
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public TicketModelTrainer(IConfiguration configuration, ILogger<TicketModelTrainer> logger)
    {
        var dataDir = Path.Combine(AppContext.BaseDirectory, "Data");
        _dataPath = configuration.GetValue("ML:DataPath", Path.Combine(dataDir, "tickets.csv"))!;
        _modelPath = configuration.GetValue("ML:ModelPath", Path.Combine(dataDir, "ticket-model.zip"))!;
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public TrainingMetrics Train()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        IDataView data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model...");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var result = new TrainingMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            ConfusionMatrix = metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };

        _logger.LogInformation(
            "Model metrics — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            result.MicroAccuracy, result.MacroAccuracy, result.LogLoss);

        Directory.CreateDirectory(Path.GetDirectoryName(_modelPath)!);
        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return result;
    }

    public static string[] GetCategoryLabels() => CategoryLabels;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketModelTrainer _trainer;

    public TicketClassifierController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketModelTrainer trainer)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
    }

    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);
        var labels = TicketModelTrainer.GetCategoryLabels();

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    [HttpPost("train")]
    public ActionResult<TrainingMetrics> Train()
    {
        var metrics = _trainer.Train();
        return Ok(metrics);
    }
}

