using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the model trainer and train on startup so the model file exists
builder.Services.AddSingleton<TicketModelTrainer>();

var app = builder.Build();

// Train the model at startup to ensure the .zip exists for PredictionEnginePool
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
trainer.Train();

// Register PredictionEnginePool after the model file is on disk.
// We re-build a small service collection scoped to the pool so that
// the pool is available for the lifetime of the app and automatically
// picks up retrained models when the file changes.
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath, watchForChanges: true);

// Rebuild the app so the pool registration takes effect
app = builder.Build();

app.MapControllers();
app.Run();

